on PDU PDU_B
{
  ethernetPacket aPacket_01;
  long result;
  result = GetEthernetPacket(this, aPacket_01); // PDU is assumed to be sent on ETH
  if (result == 0)
  {
    write("Received PDU 'PDU_B' in ETH packet with FCS %lu", aPacket_01.FCS);
  }
  else
  {
    write("Error accessing PDU!");
  }
}
